import React, { useState, useEffect } from 'react';
import {
  Box,
  Card,
  CardContent,
  Grid,
  Typography,
  IconButton,
  Stack,
  CircularProgress,
  LinearProgress,
  Chip,
  Switch,
  FormControlLabel,
  useTheme,
  Button,
} from '@mui/material';
import {
  Memory as MemoryIcon,
  Storage as StorageIcon,
  Speed as SpeedIcon,
  CloudSync as CloudSyncIcon,
  DnsOutlined as DnsIcon,
  PowerSettingsNew as PowerIcon,
  Refresh as RefreshIcon,
  OpenInNew as OpenInNewIcon,
  LightMode as LightModeIcon,
  DarkMode as DarkModeIcon,
} from '@mui/icons-material';
import { getSystemInfo, getSystemStatus, startService, stopService } from '../services/api';
import { getCommonStyles } from '../styles/commonStyles';

const Dashboard = ({ mode, setMode, onDashboardClick = () => {} }) => {
  const theme = useTheme();
  const styles = getCommonStyles(theme);
  const [loading, setLoading] = useState(false);
  const [systemInfo, setSystemInfo] = useState({
    hostname: '',
    platform: '',
    arch: '',
    uptime: 0,
    cpu_usage: 0,
    memory_total: 0,
    memory_used: 0,
  });
  const [serviceStatus, setServiceStatus] = useState({
    singbox: {
      running: false,
      version: '',
    },
    mosdns: {
      running: false,
      version: '',
    },
  });
  const [sysStatus, setSysStatus] = useState({
    subscriptions: [],
  });

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 5000); // 每5秒更新一次
    return () => clearInterval(interval);
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);
      const [sysInfo, sysStatus] = await Promise.all([
        getSystemInfo(),
        getSystemStatus(),
      ]);

      // 更新系统信息
      setSystemInfo({
        hostname: sysInfo.hostname || '',
        platform: sysInfo.platform || '',
        arch: sysInfo.arch || '',
        uptime: sysInfo.uptime || 0,
        cpu_usage: sysInfo.cpu_usage || 0,
        memory_total: sysInfo.memory_total || 0,
        memory_used: sysInfo.memory_used || 0,
      });

      // 更新服务状态
      setServiceStatus({
        singbox: {
          running: sysStatus.services?.singbox || false,
          version: sysStatus.versions?.singbox || '',
        },
        mosdns: {
          running: sysStatus.services?.mosdns || false,
          version: sysStatus.versions?.mosdns || '',
        },
      });

      // 更新系统状态（包含订阅信息）
      setSysStatus(sysStatus);
    } catch (error) {
      console.error('Failed to fetch data:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleServiceToggle = async (service, status) => {
    try {
      setLoading(true);
      if (status) {
        await stopService(service);
      } else {
        await startService(service);
      }
      await fetchData();
    } catch (error) {
      console.error(`Failed to toggle ${service}:`, error);
    } finally {
      setLoading(false);
    }
  };

  const formatBytes = (bytes) => {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return `${parseFloat((bytes / Math.pow(k, i)).toFixed(2))} ${sizes[i]}`;
  };

  const formatUptime = (seconds) => {
    const days = Math.floor(seconds / (24 * 60 * 60));
    const hours = Math.floor((seconds % (24 * 60 * 60)) / (60 * 60));
    const minutes = Math.floor((seconds % (60 * 60)) / 60);
    return `${days}天 ${hours}小时 ${minutes}分钟`;
  };

  const formatDate = (dateString) => {
    if (!dateString) return '-';
    const date = new Date(dateString);
    return date.toLocaleString('zh-CN', {
      year: 'numeric',
      month: '2-digit',
      day: '2-digit',
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
    });
  };

  const handleUpdateAllSubscriptions = async () => {
    try {
      setLoading(true);
      await fetchData();
    } catch (error) {
      console.error('Failed to update all subscriptions:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleUpdateSubscription = async (id) => {
    try {
      setLoading(true);
      // 这里可以添加更新单个订阅的 API 调用
      await fetchData();
    } catch (error) {
      console.error(`Failed to update subscription ${id}:`, error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box>
      <Card sx={styles.headerCard}>
        <CardContent sx={{ py: 1.5, px: 2, '&:last-child': { pb: 1.5 } }}>
          <Stack direction="row" alignItems="center" justifyContent="space-between">
            <Stack direction="row" alignItems="center" spacing={2}>
              <Typography variant="h5" sx={{ fontWeight: 500, color: 'inherit' }}>
                仪表盘
              </Typography>
              {loading && (
                <Box sx={{ display: 'flex', alignItems: 'center' }}>
                  <CircularProgress size={20} thickness={4} sx={{ color: 'rgba(255,255,255,0.8)' }} />
                </Box>
              )}
            </Stack>
            <Stack direction="row" spacing={1}>
              {onDashboardClick && (
                <IconButton
                  size="small"
                  onClick={onDashboardClick}
                  sx={styles.iconButton}
                >
                  <OpenInNewIcon fontSize="small" />
                </IconButton>
              )}
              <IconButton
                size="small"
                onClick={() => setMode(mode === 'dark' ? 'light' : 'dark')}
                sx={styles.iconButton}
              >
                {mode === 'dark' ? <LightModeIcon fontSize="small" /> : <DarkModeIcon fontSize="small" />}
              </IconButton>
            </Stack>
          </Stack>
        </CardContent>
      </Card>

      {loading && <LinearProgress sx={{ mb: 1 }} />}

      <Grid container spacing={1.5}>
        {/* 第一行：系统信息、CPU使用率、内存使用率、网络状态 */}
        <Grid item xs={12} sm={6} md={3}>
          <Card sx={styles.card}>
            <CardContent>
              <Stack spacing={1}>
                <Typography variant="h6" sx={{ fontWeight: 500 }}>系统信息</Typography>
                <Stack spacing={0.5}>
                  <Typography variant="body2" color="text.secondary">
                    操作系统：{systemInfo.os}
                  </Typography>
                  <Typography variant="body2" color="text.secondary">
                    架构：{systemInfo.arch}
                  </Typography>
                  <Typography variant="body2" color="text.secondary">
                    运行时间：{systemInfo.uptime}
                  </Typography>
                </Stack>
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        <Grid item xs={12} sm={6} md={3}>
          <Card sx={styles.card}>
            <CardContent>
              <Stack spacing={1}>
                <Typography variant="h6" sx={{ fontWeight: 500 }}>CPU 使用率</Typography>
                <Box sx={{ position: 'relative', display: 'inline-flex', justifyContent: 'center', width: '100%' }}>
                  <CircularProgress
                    variant="determinate"
                    value={systemInfo.cpuUsage}
                    size={80}
                    thickness={4}
                    sx={{
                      color: (theme) =>
                        systemInfo.cpuUsage > 80 ? theme.palette.error.main :
                        systemInfo.cpuUsage > 60 ? theme.palette.warning.main :
                        theme.palette.success.main
                    }}
                  />
                  <Box sx={{
                    position: 'absolute',
                    top: '50%',
                    left: '50%',
                    transform: 'translate(-50%, -50%)',
                    textAlign: 'center'
                  }}>
                    <Typography variant="body1" sx={{ fontWeight: 500 }}>
                      {Math.round(systemInfo.cpuUsage)}%
                    </Typography>
                  </Box>
                </Box>
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        <Grid item xs={12} sm={6} md={3}>
          <Card sx={styles.card}>
            <CardContent>
              <Stack spacing={1}>
                <Typography variant="h6" sx={{ fontWeight: 500 }}>内存使用率</Typography>
                <Box sx={{ position: 'relative', display: 'inline-flex', justifyContent: 'center', width: '100%' }}>
                  <CircularProgress
                    variant="determinate"
                    value={systemInfo.memoryUsage}
                    size={80}
                    thickness={4}
                    sx={{
                      color: (theme) =>
                        systemInfo.memoryUsage > 80 ? theme.palette.error.main :
                        systemInfo.memoryUsage > 60 ? theme.palette.warning.main :
                        theme.palette.success.main
                    }}
                  />
                  <Box sx={{
                    position: 'absolute',
                    top: '50%',
                    left: '50%',
                    transform: 'translate(-50%, -50%)',
                    textAlign: 'center'
                  }}>
                    <Typography variant="body1" sx={{ fontWeight: 500 }}>
                      {Math.round(systemInfo.memoryUsage)}%
                    </Typography>
                  </Box>
                </Box>
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        <Grid item xs={12} sm={6} md={3}>
          <Card sx={styles.card}>
            <CardContent>
              <Stack spacing={1}>
                <Typography variant="h6" sx={{ fontWeight: 500 }}>网络状态</Typography>
                <Stack spacing={0.5}>
                  <Typography variant="body2" color="text.secondary">
                    上传：{formatBytes(systemInfo.networkUpload)}/s
                  </Typography>
                  <Typography variant="body2" color="text.secondary">
                    下载：{formatBytes(systemInfo.networkDownload)}/s
                  </Typography>
                  <Typography variant="body2" color="text.secondary">
                    连接数：{systemInfo.connections}
                  </Typography>
                </Stack>
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        {/* 第二行：服务控制卡片 */}
        <Grid item xs={12}>
          <Card sx={styles.card}>
            <CardContent>
              <Stack spacing={2}>
                <Typography variant="h6" sx={{ fontWeight: 500 }}>服务控制</Typography>
                <Grid container spacing={2}>
                  {services.map((service) => (
                    <Grid item xs={12} sm={6} md={3} key={service.name}>
                      <Card sx={{
                        ...styles.serviceCard,
                        borderColor: service.active ? 'success.main' : 'error.main',
                      }}>
                        <CardContent>
                          <Stack direction="row" justifyContent="space-between" alignItems="center">
                            <Stack spacing={0.5}>
                              <Typography variant="subtitle1" sx={{ fontWeight: 500 }}>
                                {service.name}
                              </Typography>
                              <Typography variant="body2" color="text.secondary">
                                {service.description}
                              </Typography>
                            </Stack>
                            <Switch
                              checked={service.active}
                              onChange={() => handleServiceToggle(service.id)}
                              disabled={loading}
                            />
                          </Stack>
                        </CardContent>
                      </Card>
                    </Grid>
                  ))}
                </Grid>
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        {/* 第三行：订阅信息 */}
        <Grid item xs={12}>
          <Card sx={styles.card}>
            <CardContent>
              <Stack spacing={2}>
                <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <Typography variant="h6" sx={{ fontWeight: 500 }}>订阅信息</Typography>
                  <Button
                    variant="contained"
                    size="small"
                    startIcon={<SyncIcon />}
                    onClick={handleUpdateAllSubscriptions}
                    disabled={loading}
                    sx={styles.actionButton}
                  >
                    更新全部
                  </Button>
                </Box>
                <Grid container spacing={2}>
                  {subscriptions.map((subscription) => (
                    <Grid item xs={12} sm={6} md={4} key={subscription.id}>
                      <Card sx={styles.subscriptionCard}>
                        <CardContent>
                          <Stack spacing={1}>
                            <Stack direction="row" justifyContent="space-between" alignItems="center">
                              <Typography variant="subtitle1" sx={{ fontWeight: 500 }}>
                                {subscription.name}
                              </Typography>
                              <Button
                                variant="outlined"
                                size="small"
                                startIcon={<SyncIcon />}
                                onClick={() => handleUpdateSubscription(subscription.id)}
                                disabled={loading}
                                sx={styles.outlinedButton}
                              >
                                更新
                              </Button>
                            </Stack>
                            <Stack spacing={0.5}>
                              <Typography variant="body2" color="text.secondary">
                                节点数量：{subscription.nodeCount}
                              </Typography>
                              <Typography variant="body2" color="text.secondary">
                                上次更新：{subscription.lastUpdate}
                              </Typography>
                              <Typography variant="body2" color="text.secondary">
                                过期时间：{subscription.expireTime}
                              </Typography>
                            </Stack>
                          </Stack>
                        </CardContent>
                      </Card>
                    </Grid>
                  ))}
                </Grid>
              </Stack>
            </CardContent>
          </Card>
        </Grid>
      </Grid>
    </Box>
  );
};

export default Dashboard;
